package main.rice.test;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * Represents a single test case: an ordered list of Python objects, one per argument
 * to the function under test.
 */
public class TestCase {

    /**
     * The list of arguments for this test case.
     */
    private final List<APyObj> args;

    /**
     * Constructs a TestCase with the given list of arguments.
     *
     * @param args the arguments for this test case
     */
    public TestCase(List<? extends APyObj> args) {
        this.args = new ArrayList<>(args);
    }

    /**
     * Returns the list of arguments for this test case.
     *
     * @return the list of arguments
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Compares this TestCase to another object for equality by comparing argument lists.
     *
     * @param obj the object to compare against
     * @return true if the argument lists are equal
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase other)) {
            return false;
        }
        return this.args.equals(other.args);
    }

    /**
     * Returns a hash code based on the argument list.
     *
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return this.args.hashCode();
    }

    /**
     * Returns a string representation of this test case.
     *
     * @return a string representation
     */
    @Override
    public String toString() {
        return this.args.toString();
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python list objects. The domain specifies allowed lengths.
 * Elements are generated by the left child node.
 *
 * @param <T> the type of element in the list
 */
public class PyListNode<T extends APyObj> extends AIterablePyNode<T, PyListObj<T>> {

    /**
     * Constructs a PyListNode with the given child node for element generation.
     *
     * @param child the node used to generate list elements
     */
    public PyListNode(APyNode<T> child) {
        this.leftChild = child;
    }

    /**
     * Generates all exhaustive lists. For each length in exDomain, generates all
     * ordered lists of that length using the exhaustive values of the child node
     * (with repetition allowed).
     *
     * @return a set of all exhaustive PyListObj values
     */
    @Override
    public Set<PyListObj<T>> genExVals() {
        Set<PyListObj<T>> result = new LinkedHashSet<>();
        List<T> innerVals = new ArrayList<>(this.leftChild.genExVals());

        for (Integer len : this.exDomain) {
            List<List<T>> combos = cartesianProductWithRep(innerVals, len);
            for (List<T> combo : combos) {
                result.add(new PyListObj<>(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random list. Picks a random length from ranDomain, then
     * picks that many random elements from the child node.
     *
     * @return a randomly generated PyListObj
     */
    @Override
    public PyListObj<T> genRandVal() {
        Random random = new Random();
        int len = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<T> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(this.leftChild.genRandVal());
        }
        return new PyListObj<>(elements);
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python string objects. The domain specifies allowed lengths.
 * The constructor takes a String of allowed characters rather than a child node.
 */
public class PyStringNode extends APyNode<PyStringObj> {

    /**
     * The list of characters that can appear in generated strings.
     */
    private final List<Character> allowedChars;

    /**
     * Constructs a PyStringNode with the given set of allowed characters.
     *
     * @param allowedChars a String where each character is an allowed character
     */
    public PyStringNode(String allowedChars) {
        this.allowedChars = new ArrayList<>();
        for (int i = 0; i < allowedChars.length(); i++) {
            this.allowedChars.add(allowedChars.charAt(i));
        }
    }

    /**
     * Generates all exhaustive strings. For each length in exDomain, generates all
     * strings of that length using the allowed characters (with repetition allowed).
     *
     * @return a set of all exhaustive PyStringObj values
     */
    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new LinkedHashSet<>();

        for (Integer len : this.exDomain) {
            List<List<Character>> combos = cartesianProductWithRep(this.allowedChars, len);
            for (List<Character> combo : combos) {
                StringBuilder sb = new StringBuilder();
                for (Character c : combo) {
                    sb.append(c);
                }
                result.add(new PyStringObj(sb.toString()));
            }
        }
        return result;
    }

    /**
     * Generates a single random string. Picks a random length from ranDomain, then
     * picks that many random characters from the allowed set.
     *
     * @return a randomly generated PyStringObj
     */
    @Override
    public PyStringObj genRandVal() {
        Random random = new Random();
        int len = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < len; i++) {
            sb.append(this.allowedChars.get(random.nextInt(this.allowedChars.size())));
        }
        return new PyStringObj(sb.toString());
    }

    /**
     * Generates all ordered sequences of the given length from the given list of
     * elements, with repetition allowed.
     */
    private static <T> List<List<T>> cartesianProductWithRep(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        if (length == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        List<List<T>> smaller = cartesianProductWithRep(elements, length - 1);
        for (T elem : elements) {
            for (List<T> prev : smaller) {
                List<T> newList = new ArrayList<>();
                newList.add(elem);
                newList.addAll(prev);
                result.add(newList);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * An abstract class representing a node that generates iterable Python objects
 * (lists, sets, tuples). It has a single left child node that generates the
 * elements of the iterable.
 *
 * @param <InnerType> the type of element in the iterable
 * @param <OuterType> the type of the iterable object generated
 */
public abstract class AIterablePyNode<InnerType extends APyObj, OuterType extends APyObj>
        extends APyNode<OuterType> {

    /**
     * The child node used to generate elements of the iterable.
     */
    protected APyNode<InnerType> leftChild;

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    public APyNode<InnerType> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Generates all ordered tuples of the given length from the given list of elements,
     * with repetition allowed (i.e., Cartesian product of elements with itself length
     * times).
     *
     * @param elements the elements to combine
     * @param length   the desired length
     * @param <T>      the element type
     * @return all ordered lists of the given length
     */
    protected static <T> List<List<T>> cartesianProductWithRep(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        if (length == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        List<List<T>> smaller = cartesianProductWithRep(elements, length - 1);
        for (T elem : elements) {
            for (List<T> prev : smaller) {
                List<T> newList = new ArrayList<>();
                newList.add(elem);
                newList.addAll(prev);
                result.add(newList);
            }
        }
        return result;
    }

    /**
     * Generates all combinations of the given size from the given list of elements,
     * without repetition (i.e., all subsets of size 'size').
     *
     * @param elements the elements to choose from
     * @param size     the desired subset size
     * @param <T>      the element type
     * @return all combinations as lists (preserving relative order)
     */
    protected static <T> List<List<T>> combinations(List<T> elements, int size) {
        List<List<T>> result = new ArrayList<>();
        if (size == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        if (elements.size() < size) {
            return result;
        }
        for (int i = 0; i <= elements.size() - size; i++) {
            T first = elements.get(i);
            List<List<T>> rest = combinations(elements.subList(i + 1, elements.size()), size - 1);
            for (List<T> combo : rest) {
                List<T> newList = new ArrayList<>();
                newList.add(first);
                newList.addAll(combo);
                result.add(newList);
            }
        }
        return result;
    }
}

