/**
 * A node that generates Python tuple objects. The domain specifies allowed lengths.
 * Elements are generated by the left child node. Tuples, like lists, allow duplicates
 * and maintain order, so exhaustive generation uses Cartesian product with repetition.
 *
 * @param <T> the type of element in the tuple
 */
public class PyTupleNode<T extends APyObj> extends AIterablePyNode<T, PyTupleObj<T>> {

    /**
     * Constructs a PyTupleNode with the given child node for element generation.
     *
     * @param child the node used to generate tuple elements
     */
    public PyTupleNode(APyNode<T> child) {
        this.leftChild = child;
    }

    /**
     * Generates all exhaustive tuples. For each length in exDomain, generates all
     * ordered tuples of that length using the exhaustive values of the child node
     * (with repetition allowed).
     *
     * @return a set of all exhaustive PyTupleObj values
     */
    @Override
    public Set<PyTupleObj<T>> genExVals() {
        Set<PyTupleObj<T>> result = new LinkedHashSet<>();
        List<T> innerVals = new ArrayList<>(this.leftChild.genExVals());

        for (Integer len : this.exDomain) {
            List<List<T>> combos = cartesianProductWithRep(innerVals, len);
            for (List<T> combo : combos) {
                result.add(new PyTupleObj<>(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random tuple. Picks a random length from ranDomain, then
     * picks that many random elements from the child node.
     *
     * @return a randomly generated PyTupleObj
     */
    @Override
    public PyTupleObj<T> genRandVal() {
        Random random = new Random();
        int len = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<T> elements = new ArrayList<>();
        for (int i = 0; i < len; i++) {
            elements.add(this.leftChild.genRandVal());
        }
        return new PyTupleObj<>(elements);
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python dictionary objects. The domain specifies allowed sizes
 * (number of key-value pairs). Keys are generated by the left child node, and values
 * are generated by the right child node.
 *
 * @param <K> the type of dictionary keys
 * @param <V> the type of dictionary values
 */
public class PyDictNode<K extends APyObj, V extends APyObj> extends APyNode<PyDictObj<K, V>> {

    /**
     * The node used to generate dictionary keys.
     */
    private final APyNode<K> leftChild;

    /**
     * The node used to generate dictionary values.
     */
    private final APyNode<V> rightChild;

    /**
     * Constructs a PyDictNode with the given key and value child nodes.
     *
     * @param leftChild  the node for generating keys
     * @param rightChild the node for generating values
     */
    public PyDictNode(APyNode<K> leftChild, APyNode<V> rightChild) {
        this.leftChild = leftChild;
        this.rightChild = rightChild;
    }

    /**
     * Returns the left child (key generator) node.
     *
     * @return the left child node
     */
    public APyNode<K> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Returns the right child (value generator) node.
     *
     * @return the right child node
     */
    public APyNode<V> getRightChild() {
        return this.rightChild;
    }

    /**
     * Generates all exhaustive dictionaries. For each size in exDomain, generates all
     * possible dictionaries of that size. Keys are chosen without replacement from the
     * key node's exhaustive values, and each key is independently mapped to any value
     * from the value node's exhaustive values.
     *
     * @return a set of all exhaustive PyDictObj values
     */
    @Override
    public Set<PyDictObj<K, V>> genExVals() {
        Set<PyDictObj<K, V>> result = new LinkedHashSet<>();
        List<K> keyVals = new ArrayList<>(this.leftChild.genExVals());
        List<V> valVals = new ArrayList<>(this.rightChild.genExVals());

        for (Integer size : this.exDomain) {
            // Get all combinations of 'size' keys (without replacement)
            List<List<K>> keyCombos = combinations(keyVals, size);
            for (List<K> keys : keyCombos) {
                // For each key combo, get all value tuples (with replacement, one per key)
                List<List<V>> valueTuples = cartesianProductWithRep(valVals, size);
                for (List<V> values : valueTuples) {
                    Map<K, V> map = new LinkedHashMap<>();
                    for (int i = 0; i < keys.size(); i++) {
                        map.put(keys.get(i), values.get(i));
                    }
                    result.add(new PyDictObj<>(map));
                }
            }
        }
        return result;
    }

    /**
     * Generates a single random dictionary. Picks a random size from ranDomain, then
     * picks that many random key-value pairs using the child nodes. Keys are collected
     * without replacement.
     *
     * @return a randomly generated PyDictObj
     */
    @Override
    public PyDictObj<K, V> genRandVal() {
        Random random = new Random();
        int size = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        Map<K, V> map = new LinkedHashMap<>();
        int maxAttempts = size * 100 + 100;
        int attempts = 0;
        while (map.size() < size && attempts < maxAttempts) {
            K key = this.leftChild.genRandVal();
            V val = this.rightChild.genRandVal();
            if (!map.containsKey(key)) {
                map.put(key, val);
            }
            attempts++;
        }
        return new PyDictObj<>(map);
    }

    /**
     * Generates all combinations of the given size from elements (without repetition).
     */
    private static <T> List<List<T>> combinations(List<T> elements, int size) {
        List<List<T>> result = new ArrayList<>();
        if (size == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        if (elements.size() < size) {
            return result;
        }
        for (int i = 0; i <= elements.size() - size; i++) {
            T first = elements.get(i);
            List<List<T>> rest = combinations(elements.subList(i + 1, elements.size()), size - 1);
            for (List<T> combo : rest) {
                List<T> newList = new ArrayList<>();
                newList.add(first);
                newList.addAll(combo);
                result.add(newList);
            }
        }
        return result;
    }

    /**
     * Generates all ordered tuples of the given length from elements, with repetition.
     */
    private static <T> List<List<T>> cartesianProductWithRep(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        if (length == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        List<List<T>> smaller = cartesianProductWithRep(elements, length - 1);
        for (T elem : elements) {
            for (List<T> prev : smaller) {
                List<T> newList = new ArrayList<>();
                newList.add(elem);
                newList.addAll(prev);
                result.add(newList);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.*;

/**
 * A node that generates Python integer objects. The exhaustive and random domains
 * are lists of integer values that can be generated.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    /**
     * Generates all exhaustive values: one PyIntObj per value in the exhaustive domain.
     *
     * @return a set of PyIntObj instances, one per value in exDomain
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new LinkedHashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    /**
     * Generates a single random PyIntObj by picking a random value from ranDomain.
     *
     * @return a randomly chosen PyIntObj
     */
    @Override
    public PyIntObj genRandVal() {
        Random random = new Random();
        int idx = random.nextInt(this.ranDomain.size());
        return new PyIntObj(this.ranDomain.get(idx));
    }
}

package main.rice.node;

import main.rice.obj.*;
import java.util.*;

/**
 * A node that generates Python set objects. The domain specifies allowed sizes.
 * Elements are generated by the left child node. Sets do not allow duplicates,
 * so exhaustive generation uses combinations without repetition.
 *
 * @param <T> the type of element in the set
 */
public class PySetNode<T extends APyObj> extends AIterablePyNode<T, PySetObj<T>> {

    /**
     * Constructs a PySetNode with the given child node for element generation.
     *
     * @param child the node used to generate set elements
     */
    public PySetNode(APyNode<T> child) {
        this.leftChild = child;
    }

    /**
     * Generates all exhaustive sets. For each size in exDomain, generates all
     * subsets of that size from the child node's exhaustive values.
     *
     * @return a set of all exhaustive PySetObj values
     */
    @Override
    public Set<PySetObj<T>> genExVals() {
        Set<PySetObj<T>> result = new LinkedHashSet<>();
        List<T> innerVals = new ArrayList<>(this.leftChild.genExVals());

        for (Integer size : this.exDomain) {
            List<List<T>> combos = combinations(innerVals, size);
            for (List<T> combo : combos) {
                Set<T> innerSet = new LinkedHashSet<>(combo);
                result.add(new PySetObj<>(innerSet));
            }
        }
        return result;
    }

    /**
     * Generates a single random set. Picks a random size from ranDomain, then
     * repeatedly calls the child node's genRandVal() to collect distinct elements.
     *
     * @return a randomly generated PySetObj
     */
    @Override
    public PySetObj<T> genRandVal() {
        Random random = new Random();
        int size = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        Set<T> elements = new LinkedHashSet<>();
        int maxAttempts = size * 100 + 100;
        int attempts = 0;
        while (elements.size() < size && attempts < maxAttempts) {
            elements.add(this.leftChild.genRandVal());
            attempts++;
        }
        return new PySetObj<>(elements);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.*;

/**
 * An abstract class representing a node in a "type tree" that can generate values of a
 * specific Python type. Each node has an exhaustive domain and a random domain, both
 * represented as lists of integers. The meaning of these integers depends on the
 * concrete subclass.
 *
 * @param <T> the type of Python object generated by this node
 */
public abstract class APyNode<T extends APyObj> {

    /**
     * The exhaustive domain for this node. For scalar types, these are the actual
     * values; for iterable types, these are the allowed sizes.
     */
    protected List<Integer> exDomain;

    /**
     * The random domain for this node. Same interpretation as exDomain.
     */
    protected List<Integer> ranDomain;

    /**
     * Returns the exhaustive domain for this node.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param domain the new exhaustive domain
     */
    public void setExDomain(List<Integer> domain) {
        this.exDomain = new ArrayList<>(domain);
    }

    /**
     * Sets the random domain for this node.
     *
     * @param domain the new random domain
     */
    public void setRanDomain(List<Integer> domain) {
        this.ranDomain = new ArrayList<>(domain);
    }

    /**
     * Generates all exhaustive values for this node based on the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value for this node based on the random domain.
     *
     * @return a randomly generated value
     */
    public abstract T genRandVal();
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * Generates a base set of test cases from a list of argument nodes. The base set
 * consists of all exhaustive test cases plus a specified number of random test cases
 * that are not duplicates of the exhaustive ones.
 */
public class BaseSetGenerator {

    /**
     * The list of argument nodes, one per function argument.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random test cases to generate.
     */
    private final int numRand;

    /**
     * Constructs a BaseSetGenerator with the given argument nodes and random count.
     *
     * @param nodes   the argument nodes
     * @param numRand the number of random test cases to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Generates all exhaustive test cases by computing the Cartesian product of each
     * argument node's exhaustive values.
     *
     * @return the set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        // Collect exhaustive values for each node
        List<List<APyObj>> allVals = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            @SuppressWarnings("unchecked")
            Set<APyObj> vals = (Set<APyObj>) node.genExVals();
            allVals.add(new ArrayList<>(vals));
        }

        // Compute Cartesian product across all argument positions
        Set<TestCase> result = new LinkedHashSet<>();
        List<List<APyObj>> product = cartesianProduct(allVals);
        for (List<APyObj> args : product) {
            result.add(new TestCase(args));
        }
        return result;
    }

    /**
     * Generates the combined base set: all exhaustive tests plus numRand random tests
     * that do not duplicate any exhaustive test case.
     *
     * @return the combined list of test cases
     */
    public List<TestCase> genBaseSet() {
        Set<TestCase> exTests = genExTests();
        List<TestCase> result = new ArrayList<>(exTests);

        // Generate random tests not in the exhaustive set
        Set<TestCase> seen = new HashSet<>(exTests);
        int maxAttempts = this.numRand * 1000 + 1000;
        int attempts = 0;
        int generated = 0;

        while (generated < this.numRand && attempts < maxAttempts) {
            TestCase tc = genOneRandTest();
            if (!seen.contains(tc)) {
                result.add(tc);
                seen.add(tc);
                generated++;
            }
            attempts++;
        }
        return result;
    }

    /**
     * Generates a single random test case by calling genRandVal() on each node.
     *
     * @return a randomly generated test case
     */
    private TestCase genOneRandTest() {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            args.add(node.genRandVal());
        }
        return new TestCase(args);
    }

    /**
     * Computes the Cartesian product of a list of lists.
     *
     * @param lists the lists to combine
     * @return all combinations, one element from each list
     */
    private static List<List<APyObj>> cartesianProduct(List<List<APyObj>> lists) {
        List<List<APyObj>> result = new ArrayList<>();
        result.add(new ArrayList<>());

        for (List<APyObj> list : lists) {
            List<List<APyObj>> newResult = new ArrayList<>();
            for (List<APyObj> existing : result) {
                for (APyObj elem : list) {
                    List<APyObj> newCombo = new ArrayList<>(existing);
                    newCombo.add(elem);
                    newResult.add(newCombo);
                }
            }
            result = newResult;
        }
        return result;
    }
}

