+package main.rice.node;
+
+import main.rice.obj.APyObj;
+import java.util.*;
+
+/**
+ * An abstract class representing a node in a "type tree" that can generate values of a
+ * specific Python type. Each node has an exhaustive domain and a random domain, both
+ * represented as lists of integers. The meaning of these integers depends on the
+ * concrete subclass.
+ *
+ * @param <T> the type of Python object generated by this node
+ */
+public abstract class APyNode<T extends APyObj> {
+
+    /**
+     * The exhaustive domain for this node. For scalar types, these are the actual
+     * values; for iterable types, these are the allowed sizes.
+     */
+    protected List<Integer> exDomain;
+
+    /**
+     * The random domain for this node. Same interpretation as exDomain.
+     */
+    protected List<Integer> ranDomain;
+
+    /**
+     * Returns the exhaustive domain for this node.
+     *
+     * @return the exhaustive domain
+     */
+    public List<Integer> getExDomain() {
+        return this.exDomain;
+    }
+
+    /**
+     * Returns the random domain for this node.
+     *
+     * @return the random domain
+     */
+    public List<Integer> getRanDomain() {
+        return this.ranDomain;
+    }
+
+    /**
+     * Sets the exhaustive domain for this node.
+     *
+     * @param domain the new exhaustive domain
+     */
+    public void setExDomain(List<Integer> domain) {
+        this.exDomain = new ArrayList<>(domain);
+    }
+
+    /**
+     * Sets the random domain for this node.
+     *
+     * @param domain the new random domain
+     */
+    public void setRanDomain(List<Integer> domain) {
+        this.ranDomain = new ArrayList<>(domain);
+    }
+
+    /**
+     * Generates all exhaustive values for this node based on the exhaustive domain.
+     *
+     * @return a set of all exhaustive values
+     */
+    public abstract Set<T> genExVals();
+
+    /**
+     * Generates a single random value for this node based on the random domain.
+     *
+     * @return a randomly generated value
+     */
+    public abstract T genRandVal();
+}
