+                result.add(new PySetObj<>(innerSet));
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random set. Picks a random size from ranDomain, then
+     * repeatedly calls the child node's genRandVal() to collect distinct elements.
