+ * A node that generates Python string objects. The domain specifies allowed lengths.
+ * The constructor takes a String of allowed characters rather than a child node.
+ */
+public class PyStringNode extends APyNode<PyStringObj> {
+
+    /**
+     * The list of characters that can appear in generated strings.
+     */
+    private final List<Character> allowedChars;
+
+    /**
+     * Constructs a PyStringNode with the given set of allowed characters.
+     *
+     * @param allowedChars a String where each character is an allowed character
+     */
+    public PyStringNode(String allowedChars) {
+        this.allowedChars = new ArrayList<>();
+        for (int i = 0; i < allowedChars.length(); i++) {
+            this.allowedChars.add(allowedChars.charAt(i));
+        }
+    }
+
+    /**
+     * Generates all exhaustive strings. For each length in exDomain, generates all
+     * strings of that length using the allowed characters (with repetition allowed).
+     *
+     * @return a set of all exhaustive PyStringObj values
+     */
+    @Override
+    public Set<PyStringObj> genExVals() {
+        Set<PyStringObj> result = new LinkedHashSet<>();
