+        for (Integer len : this.exDomain) {
+            List<List<Character>> combos = cartesianProductWithRep(this.allowedChars, len);
+            for (List<Character> combo : combos) {
+                StringBuilder sb = new StringBuilder();
+                for (Character c : combo) {
+                    sb.append(c);
+                }
+                result.add(new PyStringObj(sb.toString()));
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random string. Picks a random length from ranDomain, then
