+        int len = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
+        StringBuilder sb = new StringBuilder();
+        for (int i = 0; i < len; i++) {
+            sb.append(this.allowedChars.get(random.nextInt(this.allowedChars.size())));
+        }
+        return new PyStringObj(sb.toString());
+    }
+
+    /**
+     * Generates all ordered sequences of the given length from the given list of
+     * elements, with repetition allowed.
+     */
+    private static <T> List<List<T>> cartesianProductWithRep(List<T> elements, int length) {
