+        for (T elem : elements) {
+            for (List<T> prev : smaller) {
+                List<T> newList = new ArrayList<>();
+                newList.add(elem);
+                newList.addAll(prev);
+                result.add(newList);
+            }
+        }
+        return result;
+    }
