+ * Elements are generated by the left child node. Tuples, like lists, allow duplicates
+ * and maintain order, so exhaustive generation uses Cartesian product with repetition.
+ *
+ * @param <T> the type of element in the tuple
+ */
+public class PyTupleNode<T extends APyObj> extends AIterablePyNode<T, PyTupleObj<T>> {
+
+    /**
+     * Constructs a PyTupleNode with the given child node for element generation.
+     *
+     * @param child the node used to generate tuple elements
+     */
+    public PyTupleNode(APyNode<T> child) {
+        this.leftChild = child;
+    }
+
+    /**
+     * Generates all exhaustive tuples. For each length in exDomain, generates all
+     * ordered tuples of that length using the exhaustive values of the child node
+     * (with repetition allowed).
+     *
+     * @return a set of all exhaustive PyTupleObj values
+     */
+    @Override
+    public Set<PyTupleObj<T>> genExVals() {
+        Set<PyTupleObj<T>> result = new LinkedHashSet<>();
+        List<T> innerVals = new ArrayList<>(this.leftChild.genExVals());
+
+        for (Integer len : this.exDomain) {
+            List<List<T>> combos = cartesianProductWithRep(innerVals, len);
+            for (List<T> combo : combos) {
+                result.add(new PyTupleObj<>(combo));
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random tuple. Picks a random length from ranDomain, then
+     * picks that many random elements from the child node.
+     *
+     * @return a randomly generated PyTupleObj
+     */
+    @Override
+    public PyTupleObj<T> genRandVal() {
+        Random random = new Random();
+        int len = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
+        List<T> elements = new ArrayList<>();
+        for (int i = 0; i < len; i++) {
+            elements.add(this.leftChild.genRandVal());
+        }
+        return new PyTupleObj<>(elements);
+    }
+}
